import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"G07 研發成果 — 力成科技 (6239)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6239_力成/20260617/G07_研發成果.md","filePath":"審計報告庫/經營審計/6239_力成/20260617/G07_研發成果.md"}'),n={name:"審計報告庫/經營審計/6239_力成/20260617/G07_研發成果.md"};function i(o,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="g07-研發成果-—-力成科技-6239" tabindex="-1">G07 研發成果 — 力成科技 (6239) <a class="header-anchor" href="#g07-研發成果-—-力成科技-6239" aria-label="Permalink to &quot;G07 研發成果 — 力成科技 (6239)&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>審視力成科技的研發投入（費用、人力、方向）、技術成果（專利、製程、新產品）以及研發轉化為商業價值的效率。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>2025年研發費用率9.8%為封測同業最高，累計1,352件專利。FOPLP良率突破95%邁向量產，CPO光學引擎完成驗證，研發成果商業化潛力明確。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>研發費用率9.8%為封測同業最高，累計1,352件專利（3D封裝佔58%）。FOPLP良率從70%提升至95%以上，Hybrid Bonding間距達0.8μm（業界最細），車用ASIL-D認證18項（全球OSAT最多）。研發轉化效率高，技術領先明確。（數據來源：法說會備忘錄、YouTube商業分析）</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>力成科技的研發策略與具體成果分析：</p><p><strong>一、研發投入規模</strong> 以2025年營收749.29億元、研發費用率9.8%推估，年度研發費用約73億元。相較於日月光（營收約6,000億、研發率約5-6%即約300-360億），力成絕對金額雖低但相對投入佔比更高，顯示研發為公司核心戰略。500億元資本支出中約300億元用於先進封裝（FOPLP+友達廠投資）。</p><p><strong>二、關鍵技術成果</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">技術項目</th><th style="text-align:left;">進度</th><th style="text-align:left;">商業影響</th></tr></thead><tbody><tr><td style="text-align:left;">FOPLP</td><td style="text-align:left;">良率&gt;95%，2026H2認證、2027H1量產</td><td style="text-align:left;">每年數十億營收增量</td></tr><tr><td style="text-align:left;">CPO光學引擎</td><td style="text-align:left;">工程驗證完成，2027-2028量產</td><td style="text-align:left;">矽光子關鍵技術</td></tr><tr><td style="text-align:left;">Hybrid Bonding</td><td style="text-align:left;">間距0.8μm量產</td><td style="text-align:left;">AI/HPC晶片封裝</td></tr><tr><td style="text-align:left;">HBM4封裝</td><td style="text-align:left;">開發中</td><td style="text-align:left;">記憶體封測升級</td></tr><tr><td style="text-align:left;">車用ASIL-D</td><td style="text-align:left;">18項認證完成</td><td style="text-align:left;">車用電子市場擴張</td></tr></tbody></table><p><strong>三、專利布局策略</strong> 力成專利分布以3D封裝技術為主軸（佔58%），重點在TSV、FOPLP、Hybrid Bonding、散熱結構等領域。策略上採取「核心技術封鎖」：在FOPLP相關的RDL（重分布層）、面板級載具、大面積模塑等關鍵環節布局密集專利網，提高競爭對手的進入門檻。</p><p><strong>四、研發轉化效率</strong> 從研發到商業化的速度來看：FOPLP自2016年開始布局到2027年量產約11年，週期較長但符合先進封裝技術的發展慣例。相較之下，CPO從開發到量產（2028年）約4-5年，效率較高。Hybrid Bonding技術已成功用於CoWoS外溢訂單，2025年貢獻營收。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>🔴 空方觀點（利空風險）</strong></p><ol><li><strong>研發轉化期長</strong>：FOPLP從2016年布局到2027年量產耗時11年，先進封裝技術快速迭代下商業化速度為關鍵風險。</li><li><strong>專利差距</strong>：力成1,352件專利，對比日月光逾4,000件。若先進封裝出現顛覆性路線，專利護城河有被繞過風險。</li></ol><p><strong>🟢 多方觀點（機會可能性）</strong></p><ol><li><strong>FOPLP先發優勢</strong>：良率95%已超量產門檻，CoWoS持續吃緊下FOPLP有機會切入AI中低階封裝市場，規模數百億元。</li><li><strong>研發投入率封測業最高</strong>：9.8%顯示技術轉型決心。CPO、Hybrid Bonding量產後，力成將從記憶體封測利基廠躍升為跨記憶體、邏輯、光電的綜合封測大廠。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>tavily_search：力成 6239 研發費用 專利 技術 先進封裝（YouTube、雅虎財經、工商時報）</li><li>web_search：力成 6239 法說會（Fugle備忘錄2026/04/28、vocus分析）</li><li>web_search：力成 6239 核心產品（CMoney、鉅亨網）</li><li>tavily_search：力成 6239 FOPLP先進封裝（中央社、經濟日報）</li></ul>',21)])])}const f=e(n,[["render",i]]);export{_ as __pageData,f as default};
